+
+    // Create session with timestamps
+    let session = serde_json::json!({
+        "sessionId": "incremental-test",
+        "projectHash": "hash123",
+        "startTime": "2024-01-01T12:00:00Z",
+        "lastUpdated": "2024-01-01T12:05:00Z",
+        "messages": [
+            {
+                "type": "user",
+                "content": "Old message",
+                "timestamp": "2024-01-01T10:00:00Z"
+            },
+            {
